78: message ErrorEvaluationResponse {
79:   string flag_key = 1;
80:   string namespace_key = 2;
81:   ErrorEvaluationReason reason = 3;
82: }
83: 
84: service EvaluationService {
85:   rpc Boolean(EvaluationRequest) returns (BooleanEvaluationResponse) {}
86:   rpc Variant(EvaluationRequest) returns (VariantEvaluationResponse) {}
87:   rpc Batch(BatchEvaluationRequest) returns (BatchEvaluationResponse) {}
88: }
89: 
90: message EvaluationDistribution {
91:   string id = 1;
92:   string rule_id = 2;
93:   string variant_id = 3;
94:   string variant_key = 4;
95:   string variant_attachment = 5;
96:   float rollout = 6;
97: }
