103: }
104: 
105: message EvaluationRollout {
106:   EvaluationRolloutType type = 1;
107:   int32 rank = 2;
108:   oneof rule {
109:     EvaluationRolloutSegment segment = 3;
110:     EvaluationRolloutThreshold threshold = 4;
111:   }
112: }
113: 
114: message EvaluationRolloutThreshold {
115:   float percentage = 1;
116:   bool value = 2;
117: }
118: 
